#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-06-09

# Test: SKILL.md / agent model-ID vocabulary lint (#2338)
#
# 45+ skill files mention full Claude model IDs and previously had ZERO
# content linting — the Fable 5 launch left "opus-4-8 (latest)" claims and
# missing IDs to drift silently. This lint converts that class into a gated
# one: every `claude-(fable|opus|sonnet|haiku|3)-…` token in src/skills and
# src/agents must be a known ID in the single source of truth,
# src/hooks/src/lib/models.vocab.json (fullIds ∪ historicalIds ∪ aliases'
# targets). Catches retired IDs, typos (claude-fable-5-20260609), and
# invented variants. Add genuinely new models to the vocab file, not here.

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
REPO_ROOT="$(cd "$SCRIPT_DIR/../../.." && pwd)"
VOCAB_FILE="$REPO_ROOT/src/hooks/src/lib/models.vocab.json"

if [[ ! -f "$VOCAB_FILE" ]]; then
  echo "FAIL: vocab file missing: $VOCAB_FILE"
  exit 1
fi

# Known IDs: fullIds + historicalIds (longest-first so prefix matching below
# prefers the most specific ID).
KNOWN_IDS="$(node -p "
  const v = require('$VOCAB_FILE');
  [...new Set([...v.fullIds, ...v.historicalIds])].sort((a, b) => b.length - a.length).join('\n')
")"

FAILED=0
CHECKED=0

# Token shape: claude-<family>-<digit>... — deliberately excludes prose like
# 'claude-opus-latest'. Trailing [.*] glob suffixes (monitoring patterns like
# claude-sonnet-4.*) are stripped by the [0-9a-z-]* charset (no dots).
TOKEN_RE='claude-(fable|opus|sonnet|haiku|3)-[0-9][0-9a-z-]*'

while IFS=: read -r file line token; do
  [[ -z "$token" ]] && continue
  CHECKED=$((CHECKED + 1))
  ok=0
  while IFS= read -r known; do
    if [[ "$token" == "$known" ]]; then
      ok=1
      break
    fi
  done <<< "$KNOWN_IDS"
  if [[ $ok -eq 0 ]]; then
    echo "FAIL: ${file#"$REPO_ROOT"/}:$line — unknown model ID '$token' (not in models.vocab.json fullIds/historicalIds)"
    FAILED=1
  fi
done < <(grep -rnoE "$TOKEN_RE" "$REPO_ROOT/src/skills" "$REPO_ROOT/src/agents" \
  --include="*.md" 2>/dev/null || true)

echo ""
echo "Checked $CHECKED model-ID tokens against models.vocab.json"

if [[ $FAILED -eq 1 ]]; then
  echo "FAIL: unknown model IDs found — add real new models to src/hooks/src/lib/models.vocab.json, fix typos in place"
  exit 1
fi

echo "PASS: all model IDs in src/skills + src/agents are known vocabulary"
exit 0
